Here's a `Counter` component with clear TypeScript definitions:

```tsx
import React, { useState } from 'react';

type CounterProps = {
  initialCount?: number;
  maxCount?: number;
  onReset?: () => void;
};

export function Counter({ initialCount = 0, maxCount = Infinity, onReset }: CounterProps) {
  const [count, setCount] = useState(initialCount);

  const handleIncrement = () => {
    setCount(prev => Math.min(prev + 1, maxCount));
  };

  const handleReset = () => {
    setCount(0);
    onReset?.();
  };

  return (
    <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '16px' }}>
      <div>
        <p>Count: {count}</p>
        <button onClick={handleIncrement} disabled={count >= maxCount} style={{ padding: '8px 16px', border: '1px solid #007bff', borderRadius: '4px', cursor: 'pointer' }}>
          Increment
        </button>
      </div>
      {onReset && (
        <div>
          <button onClick={handleReset} style={{ padding: '8px 16px', border: '1px solid #dc3545', backgroundColor: '#dc3545', color: 'white', borderRadius: '4px', cursor: 'pointer' }}>
            Reset
          </button>
        </div>
      )}
    </div>
  );
}
```
It's ready to use! Would you like to add a decrement button too?

