Sure! Below is a simple React component written in TypeScript that includes a counter with increment and reset buttons:

```tsx
import React, { useState } from 'react';

interface CounterProps {
    initialCount?: number;
}

const Counter: React.FC<CounterProps> = ({ initialCount = 0 }) => {
    const [count, setCount] = useState<number>(initialCount);

    const increment = () => {
        setCount(prevCount => prevCount + 1);
    };

    const reset = () => {
        setCount(initialCount);
    };

    return (
        <div>
            <h1>Counter: {count}</h1>
            <button onClick={increment}>Increment</button>
            <button onClick={reset}>Reset</button>
        </div>
    );
};

export default Counter;
```

To use this component in your React application, you can import and include it in your main component like so:

```tsx
import React from 'react';
import Counter from './Counter';

function App() {
    return (
        <div>
            <Counter />
        </div>
    );
}

export default App;
```

This `Counter` component maintains a state for the count using `useState`, increments the count when the "Increment" button is clicked, and resets it to the initial value when the "Reset" button is clicked.

